#include <stdio.h>
#include <stdlib.h>
#include <omp.h>

#define INF 10000000

void floydWarshall(int* dist, int n) {
    int i, j, k;
    for (k = 0; k < n; k++) {
        #pragma omp parallel for private(i,j) schedule(static)
        for (i = 0; i < n; i++) {
            for (j = 0; j < n; j++) {
                int newDist = dist[i * n + k] + dist[k * n + j];
                if (newDist < dist[i * n + j]) {
                    dist[i * n + j] = newDist;
                }
            }
        }
    }
}

int main(int argc, char* argv[]) {
    if (argc != 2) {
        printf("Usage: %s <n>\n", argv[0]);
        return 1;
    }

    int n = atoi(argv[1]);
    int* dist = (int*)malloc(n * n * sizeof(int));

    // Initialize distance matrix
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            if (i == j) {
                dist[i * n + j] = 0;
            } else {
                dist[i * n + j] = (rand() % 100) + 1;
            }
        }
    }

    floydWarshall(dist, n);

    // Print the shortest path matrix
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            if (dist[i * n + j] == INF) {
                printf("INF ");
            } else {
                printf("%d ", dist[i * n + j]);
            }
        }
        printf("\n");
    }

    free(dist);
    return 0;
}
